INSERT INTO "public"."dictionary_term" (acronym, meaning, description, category, sub_category, region, is_active) VALUES ('FOB', 'Free On Board', 'El vendedor entrega la mercancía a bordo del buque designado por el comprador en el puerto de embarque. El riesgo se transmite cuando la mercancía está a bordo del buque.', 'INCOTERM', 'Maritime', 'GLOBAL', true) ON CONFLICT (acronym, category) DO NOTHING;
INSERT INTO "public"."dictionary_term" (acronym, meaning, description, category, sub_category, region, is_active) VALUES ('CIF', 'Cost, Insurance and Freight', 'El vendedor entrega la mercancía a bordo del buque o la proporciona ya así entregada. El riesgo se transmite cuando la mercancía está a bordo del buque. El vendedor debe contratar y pagar los costos y el flete necesarios para llevar la mercancía hasta el puerto de destino designado.', 'INCOTERM', 'Maritime', 'GLOBAL', true) ON CONFLICT (acronym, category) DO NOTHING;
INSERT INTO "public"."dictionary_term" (acronym, meaning, description, category, sub_category, region, is_active) VALUES ('EXW', 'Ex Works', 'El vendedor cumple su obligación de entrega cuando pone la mercancía a disposición del comprador en los locales del vendedor o en otro lugar designado (fábrica, almacén, etc.).', 'INCOTERM', 'Any Mode', 'GLOBAL', true) ON CONFLICT (acronym, category) DO NOTHING;
INSERT INTO "public"."dictionary_term" (acronym, meaning, description, category, sub_category, region, is_active) VALUES ('DDP', 'Delivered Duty Paid', 'El vendedor entrega la mercancía poniéndola a disposición del comprador, despachada para la importación, en los medios de transporte de llegada preparada para la descarga en el lugar de destino designado.', 'INCOTERM', 'Any Mode', 'GLOBAL', true) ON CONFLICT (acronym, category) DO NOTHING;
INSERT INTO "public"."dictionary_term" (acronym, meaning, description, category, sub_category, region, is_active) VALUES ('DAP', 'Delivered at Place', 'El vendedor entrega la mercancía poniéndola a disposición del comprador en el medio de transporte de llegada preparada para la descarga en el lugar de destino designado.', 'INCOTERM', 'Any Mode', 'GLOBAL', true) ON CONFLICT (acronym, category) DO NOTHING;
INSERT INTO "public"."dictionary_term" (acronym, meaning, description, category, sub_category, region, is_active) VALUES ('20GP', '20 Foot General Purpose Container', 'Contenedor estándar de 20 pies para carga seca general.', 'EQUIPMENT_TYPE', 'FCL', 'GLOBAL', true) ON CONFLICT (acronym, category) DO NOTHING;
INSERT INTO "public"."dictionary_term" (acronym, meaning, description, category, sub_category, region, is_active) VALUES ('40GP', '40 Foot General Purpose Container', 'Contenedor estándar de 40 pies para carga seca general.', 'EQUIPMENT_TYPE', 'FCL', 'GLOBAL', true) ON CONFLICT (acronym, category) DO NOTHING;
INSERT INTO "public"."dictionary_term" (acronym, meaning, description, category, sub_category, region, is_active) VALUES ('40HC', '40 Foot High Cube Container', 'Contenedor High Cube de 40 pies para carga seca, provee altura extra.', 'EQUIPMENT_TYPE', 'FCL', 'GLOBAL', true) ON CONFLICT (acronym, category) DO NOTHING;
INSERT INTO "public"."dictionary_term" (acronym, meaning, description, category, sub_category, region, is_active) VALUES ('LCL', 'Less than Container Load', 'Carga que no llena completamente un contenedor estándar, por lo que se consolida con cargas de otros remitentes.', 'MOVEMENT_TYPE', 'Ocean', 'GLOBAL', true) ON CONFLICT (acronym, category) DO NOTHING;
INSERT INTO "public"."dictionary_term" (acronym, meaning, description, category, sub_category, region, is_active) VALUES ('FCL', 'Full Container Load', 'El remitente tiene uso exclusivo del contenedor para su carga.', 'MOVEMENT_TYPE', 'Ocean', 'GLOBAL', true) ON CONFLICT (acronym, category) DO NOTHING;
INSERT INTO "public"."dictionary_term" (acronym, meaning, description, category, sub_category, region, is_active) VALUES ('AWB', 'Air Waybill', 'Documento emitido por una aerolínea o su agente que evidencia el contrato de transporte.', 'DOCUMENT_TYPE', 'Air', 'GLOBAL', true) ON CONFLICT (acronym, category) DO NOTHING;
INSERT INTO "public"."dictionary_term" (acronym, meaning, description, category, sub_category, region, is_active) VALUES ('BOL', 'Bill of Lading', 'Conocimiento de embarque marítimo emitido por un transportista al remitente como recibo de la carga.', 'DOCUMENT_TYPE', 'Ocean', 'GLOBAL', true) ON CONFLICT (acronym, category) DO NOTHING;
INSERT INTO "public"."dictionary_term" (acronym, meaning, description, category, sub_category, region, is_active) VALUES ('TEU', 'Twenty-foot Equivalent Unit', 'Unidad de medida equivalente a un contenedor de 20 pies.', 'UNIT_MEASURE', 'Capacity', 'GLOBAL', true) ON CONFLICT (acronym, category) DO NOTHING;
INSERT INTO "public"."dictionary_term" (acronym, meaning, description, category, sub_category, region, is_active) VALUES ('ETA', 'Estimated Time of Arrival', 'Fecha y hora estimadas de llegada a destino.', 'MILESTONE', 'Time', 'GLOBAL', true) ON CONFLICT (acronym, category) DO NOTHING;
INSERT INTO "public"."dictionary_term" (acronym, meaning, description, category, sub_category, region, is_active) VALUES ('ETD', 'Estimated Time of Departure', 'Fecha y hora estimadas de salida desde origen.', 'MILESTONE', 'Time', 'GLOBAL', true) ON CONFLICT (acronym, category) DO NOTHING;
